SELECT MAX(change_date) AS most_recent_change_date
FROM file_changes
WHERE file_path = 'snowflake_processes/snowflake.c';

SELECT COUNT(*) AS workspace_count
FROM workspaces
WHERE owner_id = 1;

SELECT change_type
FROM file_changes
WHERE wc_id = 1;

SELECT local_relpath
FROM workspaces
WHERE wc_id = 1;
